let hasTicket = true;
let height = 135;

if (hasTicket) {
  if (height >= 120) {
    console.log("可以玩雲霄飛車");
  } else {
    console.log("只能玩旋轉木馬");
  }
} else {
  console.log("請先購票");
}

let isMember = true;
let total = 1200;

if (isMember) {
  if (total >= 1000) {
    console.log("會員打 8 折：" + total * 0.8);
  } else {
    console.log("會員打 9 折：" + total * 0.9);
  }
} else {
  console.log("非會員，原價：" + total);
}

// 巢狀寫法
if (hasTicket) {
  if (height >= 120) {
    console.log("可以玩");
  }
}

// 扁平化寫法（用 && 合併）
if (hasTicket && height >= 120) {
  console.log("可以玩");
}

// 巢狀寫法（層層包裹）
if (age >= 18) {
  if (hasID) {
    if (hasTicket) {
      console.log("可以進場");
    } else {
      console.log("請先購票");
    }
  } else {
    console.log("請出示證件");
  }
} else {
  console.log("未成年禁止進入");
}

// Guard Clause 概念（提前處理例外）
if (age < 18) {
  console.log("未成年禁止進入");
} else if (!hasID) {
  console.log("請出示證件");
} else if (!hasTicket) {
  console.log("請先購票");
} else {
  console.log("可以進場");
}

